import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import api from '../utils/api';

const Tags = () => {
  const [tags, setTags] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');

  useEffect(() => {
    fetchTags();
  }, []);

  const fetchTags = async () => {
    try {
      const res = await api.get('/tags');
      setTags(res.data.tags);
    } catch (error) {
      console.error('Error fetching tags:', error);
    }
    setLoading(false);
  };

  const filteredTags = tags.filter(tag => 
    tag.name.toLowerCase().includes(search.toLowerCase())
  );

  if (loading) return <div className="text-center py-8">Loading...</div>;

  return (
    <div className="max-w-6xl mx-auto">
      <h1 className="text-3xl font-bold mb-6">Tags</h1>

      <div className="mb-6">
        <input
          type="text"
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          className="w-full md:w-96 border rounded-lg px-4 py-2"
          placeholder="Search tags..."
        />
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        {filteredTags.map(tag => (
          <Link
            key={tag._id}
            to={`/questions?tag=${tag.name}`}
            className="bg-white rounded-lg shadow-md p-4 hover:shadow-lg transition-shadow"
          >
            <h3 className="font-semibold text-lg text-orange-600">{tag.name}</h3>
            <p className="text-sm text-gray-600 mt-1">{tag.description || 'No description'}</p>
            <p className="text-xs text-gray-500 mt-2">{tag.count} questions</p>
          </Link>
        ))}
      </div>
    </div>
  );
};

export default Tags;
